import React, { Fragment } from "react";
import Layout from "../shop/layout";
import Login from "../shop/auth/Login";

const SuperAdminLoginPage = () => {
  return (
    <Fragment>
      <Layout>
        <div className="mx-4 mt-24 md:mx-12 md:mt-32 lg:mt-24 flex justify-center">
          <div className="w-full max-w-md bg-white shadow p-6">
            <Login />
          </div>
        </div>
      </Layout>
    </Fragment>
  );
};

export default SuperAdminLoginPage;
